INSERT INTO `game` (`id_game`, `nama_game`, `genre`, `harga_sekarang`, `developer`, `publisher`, `current_player`, `peak_player`, `good_review`, `bad_review`, `url_gambar`, `tanggal_rilis`, `deskripsi`, `created_at`, `updated_at`) VALUES
('018d937e-f0ad-7094-b86c-d8fb32a1e6b4', 'Detroit: Become Human', 'Choices Matter', 677799, 'Quantic Dream', 'Quantic Dream, Quantic Dream S.A., Sony Interactive Entertainment', 5872, 25615, 96, 4, 'https://assets.isthereanydeal.com/018d937e-f0ad-7094-b86c-d8fb32a1e6b4/banner300.jpg?t=1731958004', '2019-12-12 00:00:00', 'Inspired by the short called “Kara”, Detroit is a neo-noir thriller set in the near-future city of Detroit. Androids, who look exactly like human beings, have replaced humans in most tasks: they are workers, babysitters, gardeners, nurses, teachers, clerks. The story of Detroit starts with an unexplained incident that begins to affect the Androids. Some disappear without any explanation, others have unexpected behaviors and strangely show signs of emotions. The rumors of “deviant” androids start spreading, but no one seems to know what’s really happening... [Quantic Dream]', '2026-04-11 16:22:40', '2026-04-11 16:22:40'),
('018d937e-f491-7209-a1fa-146d1d0d30b6', 'Gorogoa', 'Puzzle', 31500, 'Buried Signal, Jason Roberts', 'Annapurna Interactive, Annapurna Games, Artifice Studio', 92, 376, 97, 3, 'https://assets.isthereanydeal.com/018d937e-f491-7209-a1fa-146d1d0d30b6/banner300.jpg?t=1760981809', '2017-12-14 00:00:00', 'Gorogoa is an elegant evolution of the puzzle genre, told through a beautifully hand-drawn story designed and illustrated by Jason Roberts.', '2026-04-11 16:23:26', '2026-04-11 16:23:26'),
('018d937e-f4d3-7185-98f0-51883414ef27', 'EVERSPACE™ 2', 'Shooter', 75199, 'Rockfish Games', 'Rockfish Games', 414, 9220, 86, 14, 'https://assets.isthereanydeal.com/018d937e-f4d3-7185-98f0-51883414ef27/banner300.jpg?t=1766407217', '2023-04-06 00:00:00', 'EVERSPACE™ 2 is a fast-paced single-player spaceship shooter with deep exploration in space and on planets, tons of loot, RPG elements, mining, and crafting. Experience a thoughtful story, set in a vivid, handcrafted open world full of secrets, puzzles, and perils.', '2026-04-11 16:25:29', '2026-04-11 16:25:29'),
('018d937e-f858-7329-9ce7-73c2ab23434e', 'CARRION', 'Villain Protagonist', 265000, 'Phobia Game Studio', 'Devolver Digital', 240, 6344, 94, 6, 'https://assets.isthereanydeal.com/018d937e-f858-7329-9ce7-73c2ab23434e/banner300.jpg?t=1760016916', '2020-07-23 00:00:00', 'In Carrion you’ll assume the role of an amorphous creature of unknown origin. Players will stalk and consume those that have imprisoned it to spread fear and panic throughout the facility. It will grow and evolve as you tear down the facility and acquire additional devastating abilities on the path to retribution that include a web-like ranged attack, the ability to bend light to become temporarily invisible, and even possess humans for maximum terror.', '2026-04-11 16:22:53', '2026-04-11 16:22:53'),
('018d937e-fa07-73ce-a8ee-b9fa1e674392', 'RESIDENT EVIL 7 biohazard', 'Horror', 135424, 'Capcom Co., Ltd., Capcom, CAPCOM Co. Ltd.', 'Capcom Co., Ltd., Capcom, Capcom Japan Inc., Capcom Ltd, CAPCOM CO. LTD, 株式会社 カプコン, Capcom (JP)', 6500, 6713, 95, 5, 'https://assets.isthereanydeal.com/018d937e-fa07-73ce-a8ee-b9fa1e674392/banner300.jpg?t=1770932106', '2016-12-26 00:00:00', 'While Resident Evil 7 draws from the series’ roots of atmospheric survival horror, it also delivers a new level of terror. In the Resident Evil games of yesteryear, players braced for fear in the first-person via the creepy door-opening scenes, and Resident Evil 7 ramps up that tension with an immersive first-person view and a photorealistic graphical style. Capcom is able to achieve a higher degree of visual fidelity thanks to the new proprietary in-house RE Engine that includes VR oriented tools. With the RE Engine plus industry leading audio and visual technologies, you experience every abhorrent detail up close and personal in Resident Evil 7. Playing the game in the PlayStation VR Mode escalates the unsettling feeling of presence to a level that horror fans have never experienced. The full gameplay experience is available in the included PlayStation VR Mode from beginning to end. No Resident Evil you’ve ever survived could prepare you for this. [Capcom]', '2026-04-11 16:24:35', '2026-04-11 16:24:35'),
('018d937e-fa3c-7148-89e9-0bc7015abc73', 'Planet Coaster', 'Simulation', 192322, 'Frontier Developments, Aspyr, Frontier Developments, Aspyr, Aspyr (Mac)', 'Frontier Developments, Aspyr Media Inc, Aspyr Media, Inc., Aspyr, Aspyr (Mac)', 2532, 18010, 91, 9, 'https://assets.isthereanydeal.com/018d937e-fa3c-7148-89e9-0bc7015abc73/banner300.jpg?t=1760462468', '2016-11-16 00:00:00', 'Planet Coaster is the future of coaster park simulation games. From the developer: We’ve created a living world where every guest is an individual with their own personality and money in their pocket. We’re giving you limitless freedom to build rides and scenery piece by piece, and to seamlessly blend them with your own hand-sculpted terrain. We’re building a connected global village where everyone can share in your creativity. And that’s just the start. We hope you’ll join us to dream, build and share the ultimate coaster parks in Planet Coaster. [Frontier]', '2026-04-11 16:24:33', '2026-04-11 16:24:33'),
('018d937e-fce8-716b-97f3-6a41f82bb9e7', 'DOOM', 'FPS', 70591, 'id Software', 'Bethesda Softworks, Bethesda, Activision, Bethesda Softworks LLC, GT Interactive Software', 848, 12885, 95, 5, 'https://assets.isthereanydeal.com/018d937e-fce8-716b-97f3-6a41f82bb9e7/banner300.jpg?t=1761636615', '2016-05-12 00:00:00', 'There is no taking cover or stopping to regenerate health in campaign mode as you beat back Hell’s raging demon hordes. Combine your arsenal of futuristic and iconic guns, upgrades, movement and an advanced melee system to knock-down, slash, stomp, crush, and blow apart demons in creative and violent ways. In multiplayer, dominate your opponents in DOOM’s signature, fast-paced arena-style combat. In both classic and all-new game modes, annihilate your enemies utilizing your personal blend of skill, powerful weapons, vertical movement, and unique power-ups that allow you to play as a demon. DOOM SnapMap is an easy-to-use game and level editor that allows for limitless gameplay experiences on every platform. Anyone can snap together and customize maps, add pre-defined or custom gameplay, and edit game logic to create new modes. Instantly play your creation or make it available to players around the world. [ID/Bethesda]', '2026-04-11 16:22:22', '2026-04-11 16:22:22'),
('018d937f-0092-708b-a363-41c4428d7adb', 'Okami HD', 'Adventure', 167797, 'Capcom Co., Ltd., Capcom', 'Capcom Japan Inc., Capcom Ltd, Capcom Co., Ltd., Capcom, CAPCOM CO. LTD, Capcom (JP)', 98, 1064, 92, 8, 'https://assets.isthereanydeal.com/018d937f-0092-708b-a363-41c4428d7adb/banner300.jpg?t=1763149349', '2017-12-12 00:00:00', 'In Okami, the legendary monster Orochi has come back to life and turned the world into a veritable wasteland. Players must assume the role of a wolf, an embodiment of the sun god Amaterasu, which is capable of wielding unimaginable power. The state of the world lies in gamer\'s hands as they must fight ominous beings and reclaim the earth from a curse that plagues it. It is crucial to help Amaterasu make the world a place where all living creatures can dwell once again. [Capcom]', '2026-04-11 16:23:51', '2026-04-11 16:23:51'),
('018d937f-00e8-729d-a917-e2f1d5bcc95d', 'What Remains of Edith Finch', 'Story Rich', 338815, 'Giant Sparrow', 'Annapurna Interactive, Annapurna Games', 182, 537, 95, 5, 'https://assets.isthereanydeal.com/018d937f-00e8-729d-a917-e2f1d5bcc95d/banner300.jpg?t=1760980842', '2017-04-24 00:00:00', 'The game is a collection of short stories. Each of those stories focuses on the death of a different Finch family member and each is meant to look and feel different from the others, the way no two people in any family are alike. [Giant Sparrow]', '2026-04-11 16:21:59', '2026-04-11 16:21:59'),
('018d937f-0481-72c2-9f37-97120a68525b', 'The Elder Scrolls V: Skyrim Special Edition', 'Open World', 569324, 'Bethesda Game Studios®, Bethesda Game Studios', 'Bethesda, Bethesda Softworks, Bethesda Softworks LLC', 29732, 67622, 94, 6, 'https://assets.isthereanydeal.com/018d937f-0481-72c2-9f37-97120a68525b/banner300.jpg?t=1761598890', '2016-10-27 00:00:00', 'Skyrim Special Edition brings the epic fantasy to life in detail. The Special Edition includes the game and add-ons with all-new features like remastered art and effects, volumetric god rays, dynamic depth of field, screen-space reflections, and more.', '2026-04-11 16:24:48', '2026-04-11 16:24:48'),
('018d937f-0482-72ab-b36c-62efeb92c2f2', 'Ni no Kuni™ II: Revenant Kingdom', 'RPG', 166800, 'Level 5, LEVEL-5 Inc., Level5 Inc.', 'BANDAI NAMCO Entertainment, Bandai Namco Entertainment Inc., Bandai Namco, Bandai Namco US, LEVEL-5 Inc.', 119, 1359, 82, 18, 'https://assets.isthereanydeal.com/018d937f-0482-72ab-b36c-62efeb92c2f2/banner300.jpg?t=1761153637', '2018-03-23 00:00:00', 'Re-enter the animated world of Ni no Kuni in the sequel to the role-playing game developed by LEVEL-5. Explore the world and experience the story in an all-new RPG adventure. LEVEL-5 reunites with Yoshiyuki Momose on character design and Music created by Joe Hisaishi in the production of the next Ni no Kuni tale.', '2026-04-11 16:22:37', '2026-04-11 16:22:37'),
('018d937f-08a5-730e-ab9f-04c285adec1c', 'Kerbal Space Program', 'Space', 219800, 'Squad, Private Division', 'Private Division, Private Division LLC, Squad, Fictions, The Kerbal Company', 15792, 15792, 95, 5, 'https://assets.isthereanydeal.com/018d937f-08a5-730e-ab9f-04c285adec1c/banner300.jpg?t=1760635287', '2015-04-27 00:00:00', 'In Kerbal Space Program you have to build a space-worthy ship, capable of flying its crew out into space without killing any of them. At your disposal is a collection of parts, which must be assembled to create a functional craft. Each part has its own function and will affect the way a ship flies (or does not). So strap yourself in, and get ready to try some Rocket Science.', '2026-04-11 16:23:05', '2026-04-11 16:23:05'),
('018d937f-09dd-729b-88aa-5496f800b3bd', 'Outer Wilds', 'Exploration', 423561, 'Mobius Digital', 'Annapurna Interactive, Annapurna Games', 1853, 7671, 95, 5, 'https://assets.isthereanydeal.com/018d937f-09dd-729b-88aa-5496f800b3bd/banner300.jpg?t=1760981233', '2019-05-28 00:00:00', 'Outer Wilds is an open world mystery about a solar system trapped in an endless time loop.', '2026-04-11 16:21:33', '2026-04-11 16:21:33'),
('018d937f-0a74-71e4-ac4c-a73a341db1a6', 'Stellaris', 'Space', 169323, 'Paradox, Paradox Development Studio', 'Paradox Interactive AB, Paradox Interactive, Paradox, Paradox Development Studio', 20592, 63343, 86, 14, 'https://assets.isthereanydeal.com/018d937f-0a74-71e4-ac4c-a73a341db1a6/banner300.jpg?t=1774473611', '2016-05-09 00:00:00', 'Featuring deep strategic gameplay, an enormous selection of alien races and emergent storytelling, Stellaris has a deeply challenging system that rewards interstellar exploration as you traverse, discover, interact and learn more about the multitude of species you will encounter during your travels. Etch your name across the cosmos by uncovering remote celestial outposts,and entire civilizations. Will you expand through war or walk the path of diplomacy to achieve your goals?', '2026-04-11 16:24:28', '2026-04-11 16:24:28'),
('018d937f-11e9-737d-b387-56c67ec8a1c6', 'Devil May Cry HD Collection', 'Hack and Slash', 421527, 'Capcom, Capcom Co., Ltd.', 'Capcom Ltd, Capcom Co., Ltd., Capcom, CAPCOM CO. LTD, Capcom (JP)', 655, 7482, 93, 7, 'https://assets.isthereanydeal.com/018d937f-11e9-737d-b387-56c67ec8a1c6/banner300.jpg?t=1768874408', '2018-03-13 00:00:00', 'Devil May Cry HD Collection brings the first three original Devil May Cry titles; Devil May Cry, Devil May Cry 2, and Devil May Cry 3: Dante\'s Awakening Special Edition together in one high definition package for the first time.', '2026-04-11 16:25:22', '2026-04-11 16:25:22'),
('018d937f-15f9-7056-8edf-2e8fa4b8f357', 'No Man\'s Sky', 'Open World', 393000, 'Hello Games', 'Hello Games, 505 Games', 21253, 110893, 83, 17, 'https://assets.isthereanydeal.com/018d937f-15f9-7056-8edf-2e8fa4b8f357/banner300.jpg?t=1775654122', '2016-08-11 00:00:00', 'No Man’s Sky is an exploration and survival game set in an infinite procedurally generated universe. Whether a distant mountain or a planet hanging low on the horizon, you can go forth there. You can fly seamlessly from the surface of a planet to another, and every star in the sky is a sun that you can visit. Where you’ll go and how fast you’ll make you way through this universe is your decision. Explore uncharted solar systems and catalog unique new forms of life. Every planet’s landscape is different from the next and populated by species never before encountered. Acquire ancient artifacts that may reveal the secrets behind the universe. Choose whether to share your discoveries with other players. You won’t see them, but they’re exploring the same universe in parallel; perhaps you’ll make your mark on their worlds as well as your own. Every solar system, planet, ocean and cave is filled with danger, and - make no mistake - you are vulnerable. Your ship and suit are fragile, and every encounter may test your skills to the limit. From dog-fighting in space to first-person combat on a planet’s surface, you will face foes ready to overwhelm you. One mistake could see you lose it all. In No Man’s Sky, every victory and every defeat is permanent. The voyage that stands before you cannot be taken lightly. You must prepare. Collect precious resources on the surfaces of planets and trade them for the ships, suits and equipment that will take you to your destiny in the stars.', '2026-04-11 16:21:25', '2026-04-11 16:21:25'),
('018d937f-17be-72b4-ac97-2a2712a897d9', 'Darkest Dungeon', 'Turn-Based Combat', 379493, 'Red Hook Studios', 'Red Hook Studios, Red Hook Studios Inc.', 5425, 20064, 91, 9, 'https://assets.isthereanydeal.com/018d937f-17be-72b4-ac97-2a2712a897d9/banner300.jpg?t=1769781944', '2016-01-19 00:00:00', 'Darkest Dungeon is a gothic roguelike RPG dungeon crawler about the psychological stresses of adventuring. You will lead a band of four heroes on a perilous side-scrolling descent, dealing with a prodigious number of threats to their bodily health, and worse, a relentless assault on their mental fortitude! Five hundred feet below the earth you will not only fight unimaginable foes, but famine, disease, and the stress of the ever-encroaching dark. Darkest Dungeon focuses on the humanity and psychological vulnerability of the heroes and asks: What emotional toll does a life of adventure take?', '2026-04-11 16:24:20', '2026-04-11 16:24:20'),
('018d937f-1805-71ae-b2fa-8d8c2c8f8342', 'Atomic Heart', 'Adventure', 197500, 'Mundfish', 'Focus Entertainment, 4Divinity, 5124, Focus Home Interactive', 900, 38245, 81, 19, 'https://assets.isthereanydeal.com/018d937f-1805-71ae-b2fa-8d8c2c8f8342/banner300.jpg?t=1764677417', '2023-02-01 00:00:00', 'In the Soviet Union of the future, in 1955, science reigns supreme. The world is on the verge of the greatest event.  You are Agent Major P-3 and you will have to find out what is really lying behind the utopian dream.', '2026-04-11 16:21:53', '2026-04-11 16:21:53'),
('018d937f-18f6-727f-b84d-7870e7ccc341', 'Lords of the Fallen', 'Souls-like', 167628, 'HEXWORKS, CI Games', 'CI Games, CI Games S.E., CI Games S.A., CIGames, BANDAI NAMCO Entertainment', 1906, 41160, 68, 32, 'https://assets.isthereanydeal.com/018d937f-18f6-727f-b84d-7870e7ccc341/banner300.jpg?t=1773255015', '2023-07-12 00:00:00', 'A vast world awaits in all-new, dark fantasy action-RPG, Lords of the Fallen. As one of the fabled Dark Crusaders, embark on an epic quest to overthrow Adyr, the demon God.', '2026-04-11 16:21:41', '2026-04-11 16:21:41'),
('018d937f-194c-7075-b7c9-a3c1fd30c467', 'Stray', 'Cats', 237000, 'BlueTwelve Studio', 'Annapurna Games, Annapurna Interactive', 884, 62803, 97, 3, 'https://assets.isthereanydeal.com/018d937f-194c-7075-b7c9-a3c1fd30c467/banner300.jpg?t=1760986023', '2022-07-19 00:00:00', 'Lost, alone and separated from family, a stray cat must untangle an ancient mystery to escape a long-forgotten cybercity and find the way home. Stray is a third-person cat adventure game set amidst the detailed neon-lit alleys of a decaying cybercity and the murky environments of its seedy underbelly.  See the world through the eyes of a stray and interact with the environment in playful ways. Stray is developed by BlueTwelve Studio, a small team from south of France mostly made of cats and a handful of humans.', '2026-04-11 16:21:22', '2026-04-11 16:21:22'),
('018d937f-1d1e-7172-a80b-3b57776007c8', 'Wolfenstein II: The New Colossus', 'FPS', 82547, 'Machine Games, Bethesda Game Studios®, MachineGames', 'Bethesda, Bethesda Softworks, Bethesda Softworks LLC', 442, 2141, 81, 19, 'https://assets.isthereanydeal.com/018d937f-1d1e-7172-a80b-3b57776007c8/banner300.jpg?t=1760030501', '2017-10-26 00:00:00', 'Wolfenstein II: The New Colossus is the highly anticipated sequel to the critically acclaimed, Wolfenstein: The New Order developed by the award-winning studio MachineGames. An exhilarating adventure brought to life by the industry-leading id Tech 6, Wolfenstein II sends players to Nazi-controlled America on a mission to recruit the boldest resistance leaders left. Fight the Nazis in iconic American locations, equip an arsenal of badass guns, and unleash new abilities to blast your way through legions of Nazi soldiers in this definitive first-person shooter. America, 1961. The Nazis maintain their stranglehold on the world. You are BJ Blazkowicz, aka Terror-Billy, member of the Resistance, scourge of the Nazi empire, and humanitys last hope for liberty. Only you have the guts, guns, and gumption to return stateside, kill every Nazi in sight, and spark the second American Revolution.', '2026-04-11 16:25:32', '2026-04-11 16:25:32'),
('018d937f-1e89-70c6-9ea4-7ab887d061ca', 'Twelve Minutes', 'Indie', 423561, 'Luis Antonio', 'Annapurna Interactive, Annapurna Games', 34, 7564, 72, 28, 'https://assets.isthereanydeal.com/018d937f-1e89-70c6-9ea4-7ab887d061ca/banner300.jpg?t=1763730315', '2021-08-19 00:00:00', 'You are doomed to live the same TWELVE MINUTES inside your apartment, unless you use your knowledge of what is going to happen, to change the outcome, and break the loop.  (Also known as \"12 Minutes\")', '2026-04-11 16:23:11', '2026-04-11 16:23:11'),
('018d937f-1e92-7265-8ad2-d01cdd79164b', 'Code Vein', 'Souls-like', 89000, 'BANDAI NAMCO Studios Inc., BANDAI NAMCO Studios', 'BANDAI NAMCO Entertainment, Bandai Namco Entertainment America Inc., Bandai Namco Entertainment Inc., Bandai Namco, Bandai Namco US, BANDAI NAMCO Studios Inc.', 564, 33804, 83, 17, 'https://assets.isthereanydeal.com/018d937f-1e92-7265-8ad2-d01cdd79164b/banner300.jpg?t=1766037317', '2019-09-26 00:00:00', 'In the not too distant future, a mysterious disaster has brought collapse to the world as we know it. Towering skyscrapers, once symbols of prosperity, are now lifeless graves of humanity\'s past pierced by the Thorns of Judgment. At the center of the destruction lies a hidden society of Revenants called Vein. This final stronghold is where the remaining few fight to survive, blessed with Gifts of power in exchange for their memories and a thirst for blood. Give into the bloodlust fully and risk becoming one of the Lost, fiendish ghouls devoid of any remaining humanity. Wandering aimlessly in search of blood, the Lost will stop at nothing to satisfy their hunger. Team up and embark on a journey to the ends of hell to unlock your past and escape your living nightmare in Code Vein.', '2026-04-11 16:22:42', '2026-04-11 16:22:42'),
('018d937f-1f18-7333-9b1d-26f49959b785', 'Gloomhaven', 'Online Co-Op', 202574, 'Asmodee Digital, Flaming Fowl Studios, Saber Interactive, Flaming Fowl Studios, and Saber Interactive Minsk', 'Asmodee Digital, Plugin Digital, Twin Sails Interactive, Plug In Digital, 430', 487, 6360, 82, 18, 'https://assets.isthereanydeal.com/018d937f-1f18-7333-9b1d-26f49959b785/banner300.jpg?t=1774281012', '2019-07-17 00:00:00', 'Whether you are drawn to Gloomhaven by the call of adventure or by an avid desire for gold glimmering in the dark, your fate will surely be the same. Gloomhaven, the digital adaptation of the acclaimed board game, mixes Tactical-RPG and dungeon-crawling.', '2026-04-11 16:23:13', '2026-04-11 16:23:13'),
('018d937f-21da-71a5-b774-323d7a867ff8', 'Borderlands 3', 'RPG', 55500, 'Gearbox Software, Gearbox Studios', '2K, 2K Games, TAKE-TWO INTERACTIVE, Gearbox Software', 3281, 91243, 81, 19, 'https://assets.isthereanydeal.com/018d937f-21da-71a5-b774-323d7a867ff8/banner300.jpg?t=1760030445', '2019-09-13 00:00:00', 'At the hard edge of the galaxy lies a group of planets ruthlessly exploited by militarized corporations. Brimming with loot and violence, this is your home – the Borderlands. Answering the call of the Siren champion Lilith, four Vault Hunters charge head-first into a spray of bullets, blood, and bandits to recover a map to ancient Vaults and prevent a universe-destroying power from falling into the wrong hands. The rest is history. Fearless renegade mercenaries on the wildest interplanetary treasure hunt of all time. FL4K is a wandering robotic tracker whose cold steel heart warms only for their pet beasts. Amara beats bad guys into pancakes with her psychic fists. Moze’s best friend is a 10-ton walking killing machine. And Zane, the semi-retired corporate hitman... well, he’s Zane.  Hunting Alone? No problem! Shoot and loot your way through the Borderlands, discovering the region’s untold stories and piling high your increasingly deadly cache of goodies and weapons. [2K Games]', '2026-04-11 16:23:28', '2026-04-11 16:23:28'),
('018d937f-2459-7030-a3cd-77a8f13b87e9', 'Dragon\'s Dogma: Dark Arisen', 'RPG', 421527, 'Capcom Co., Ltd., Capcom', 'Capcom Co., Ltd., Capcom Japan Inc., Capcom Ltd, Capcom, CAPCOM CO. LTD, Capcom (JP)', 589, 13284, 88, 12, 'https://assets.isthereanydeal.com/018d937f-2459-7030-a3cd-77a8f13b87e9/banner300.jpg?t=1768877406', '2016-01-14 00:00:00', 'A mysterious island known as Bitterblack Isle appears off the coast of Gransys. Its depths have claimed the lives of many Arisen; their voices still haunt the labyrinth that lies deep beneath its surface--a labyrinth ripe with secrets waiting to be discovered. The time to take up arms has come once again. Delve into the isle\'s depths and uncover its dark secret.', '2026-04-11 16:22:32', '2026-04-11 16:22:32'),
('018d937f-2b4b-72f9-ab75-bc33784a295d', 'Dead Cells', 'Adventure', 169323, 'Motion Twin', 'Motion Twin', 3446, 14617, 97, 3, 'https://assets.isthereanydeal.com/018d937f-2b4b-72f9-ab75-bc33784a295d/banner300.jpg?t=1772727316', '2017-05-10 00:00:00', 'Dead Cells is a rogue-lite, metroidvania action-platformer. You\'ll explore a sprawling, ever-changing castle... assuming you’re able to fight your way past its keepers in 2D souls-lite combat. No checkpoints. Kill, die, learn, repeat.', '2026-04-11 16:24:54', '2026-04-11 16:24:54'),
('018d937f-2bba-710d-aa7f-64f220f04817', 'Fallout 4', 'Open World', 137732, 'Bethesda Game Studios®, Bethesda Game Studios', 'Bethesda, Bethesda Softworks', 0, 187468, 81, 19, 'https://assets.isthereanydeal.com/018d937f-2bba-710d-aa7f-64f220f04817/banner300.jpg?t=1764696912', '2015-11-09 00:00:00', 'As the sole survivor of Vault 111, you enter a world destroyed by nuclear war. Every second is a fight for survival, and every choice is yours. Only you can rebuild and determine the fate of the Wasteland. Welcome home.', '2026-04-11 16:25:06', '2026-04-11 16:25:06'),
('018d937f-2dc1-71a9-9039-0587a6445b86', 'Rain World', 'Difficult', 476282, 'Videocult', 'Akupara Games', 0, 10745, 94, 6, 'https://assets.isthereanydeal.com/018d937f-2dc1-71a9-9039-0587a6445b86/banner300.jpg?t=1772228169', '2017-03-27 00:00:00', 'Assume the role of a nomadic slugcat, both predator and prey in a broken ecosystem. Grab your spear and brave the industrial wastes, hunting enough food to survive, but be wary— other, bigger creatures have the same plan... and slugcats look delicious.', '2026-04-11 16:23:31', '2026-04-11 16:23:31'),
('018d937f-2dcc-7017-8591-df882109f3e9', 'Journey', 'Beautiful', 63560, 'thatgamecompany', 'Annapurna Interactive, Annapurna Games', 113, 3075, 94, 6, 'https://assets.isthereanydeal.com/018d937f-2dcc-7017-8591-df882109f3e9/banner300.jpg?t=1760986824', '2019-06-06 00:00:00', 'Enter the world of Journey, the third game from indie developers thatgamecompany (creators of \"flOw\" and \"Flower\"). Journey is an interactive parable, an anonymous online adventure to experience a person’s life passage and their intersections with other’s. You wake alone and surrounded by miles of burning, sprawling desert, and soon discover the looming mountaintop which is your goal. Faced with rolling sand dunes, age-old ruins, caves and howling winds, your passage will not be an easy one. The goal is to get to the mountaintop, but the experience is discovering who you are, what this place is, and what is your purpose. Travel and explore this ancient, mysterious world alone, or with a stranger you meet along the way. Soar above ruins and glide across sands as you discover the secrets of a forgotten civilization. [thatgamecompany]', '2026-04-11 16:22:04', '2026-04-11 16:22:04'),
('018d937f-2e7b-7133-b8fc-15dbd2f1f035', 'Graveyard Keeper', 'Pixel Graphics', 248984, 'Lazy Bear Games', 'tinyBuild, tinyBuild LLC, tinyBuild Games, Tiny Build Games', 36537, 36974, 86, 14, 'https://assets.isthereanydeal.com/018d937f-2e7b-7133-b8fc-15dbd2f1f035/banner300.jpg?t=1775826918', '2018-08-14 00:00:00', 'Build and manage a medieval graveyard while facing ethical dilemmas and making questionable decisions. Welcome to Graveyard Keeper, the most inaccurate medieval cemetery sim of the year.', '2026-04-11 16:21:20', '2026-04-11 16:21:20'),
('018d937f-2ed1-7268-a330-a02b70043f44', 'Remnant: From the Ashes', 'Souls-like', 677799, 'Gunfire Games', 'Arc Games, Gearbox Publishing, THQ Nordic GmbH, THQ Nordic, 680', 1104, 48153, 84, 16, 'https://assets.isthereanydeal.com/018d937f-2ed1-7268-a330-a02b70043f44/banner300.jpg?t=1764666311', '2019-08-19 00:00:00', 'The world has been thrown into chaos by an ancient evil from another dimension. As one of the last remnants of humanity, you must set out alone or alongside up to two other survivors to face down hordes of deadly enemies to try to carve a foothold, rebuild, and retake what was lost.', '2026-04-11 16:25:35', '2026-04-11 16:25:35'),
('018d937f-3827-71fe-8758-0d0dff13c065', 'Ni no Kuni Wrath of the White Witch™ Remastered', 'RPG', 104068, 'QLOC, QLOC, LEVEL-5 Inc., Level5 Inc., Level5', 'Bandai Namco Entertainment Inc., BANDAI NAMCO Entertainment, Bandai Namco, Bandai Namco Entertainment America Inc., Bandai Namco US, QLOC', 81, 1142, 83, 17, 'https://assets.isthereanydeal.com/018d937f-3827-71fe-8758-0d0dff13c065/banner300.jpg?t=1771959109', '2019-09-20 00:00:00', 'Ni no Kuni: Wrath of the White Witch Remastered = Journey back to the other world in Ni no Kuni: Wrath of the White Witch. LEVEL-5\'s classic tale returns better than ever. Join Oliver as he embarks on an adventure through a world inhabited by new friends and ferocious foes alike in the hopes of bringing back his mother after a tragic incident. With a copy of the Wizard\'s Companion in his hand and his trusty friend Drippy by his side, he will travel across this rich fantasy world to tame familiars, take on enemies, and overcome the countless challenges that stand between him and his mother\'s salvation.\r\n\r\nFeatures:\r\n\r\nThis charming tale unfolds through the use of animation storyboarded and created by the legendary Studio Ghibli and music composed by the renowned Joe Hisaishi. Ni no Kuni: Wrath of the White Witch combines beautiful animated visuals, masterful storytelling, and a sweeping score to create an epic role-playing adventure like no other.\r\n\r\n* TAKE THE OTHER WORLD WITH YOU - Take Ni no Kuni: Wrath of the White Witch wherever you go on Nintendo Switch\r\n* ALL-STAR PRODUCTION - LEVEL-5\'s mastery of the RPG genre is combined with Studio Ghibli\'s world-class animation and\r\nmusic composed by the renowned Joe Hisaishi\r\n* CAPTIVATING STORY - A charming yet tragic tale unfolds through the use of animation storyboarded and created by Studio\r\nGhibli with English and Japanese voice-overs\r\n* ROLE-PLAYING MASTERY - A rich mixture of familiar RPG elements, expertly crafted and designed, and featuring dozens of\r\nlocations to explore, hundreds of creatures to battle, and a wealth of quests and secrets to uncover\r\n* DYNAMIC COMBAT - Switch freely between characters and familiars in an exciting battle system that combines real-time and\r\nturn-based tactical elements', '2026-04-11 16:25:14', '2026-04-11 16:25:14'),
('018d937f-384e-7122-bee0-26e3b8077924', 'DRAGON BALL Z: KAKAROT', 'Action', 338815, 'CyberConnect2, CyberConnect2 Co. Ltd.', 'BANDAI NAMCO Entertainment, Bandai Namco Entertainment Inc., Bandai Namco US, CyberConnect2 Co., Ltd.', 481, 25844, 93, 7, 'https://assets.isthereanydeal.com/018d937f-384e-7122-bee0-26e3b8077924/banner300.jpg?t=1769153706', '2020-01-17 00:00:00', 'Relive the story of Goku in DRAGON BALL Z: KAKAROT! Beyond the epic battles, experience life in the DRAGON BALL Z world as you fight, fish, eat, and train with Goku. Explore the new areas and adventures as you advance through the story and form powerful bonds with other heroes from the DRAGON BALL Z universe. \r\n\r\nExperience the Story\r\nExperience the story of DRAGON BALL Z from epic events to light-hearted side quests, including never-before-seen story moments that answer some burning questions of Dragon Ball lore for the first time!\r\n\r\nIconic DRAGON BALL Z\r\nPlay through iconic DRAGON BALL Z battles on a scale unlike any other. Fight across vast battlefields with destructible environments and experience epic boss battles that will test the limits of your combat abilities. Increase your power level and rise to the challenge! \r\n\r\nDon\'t Just Fight As Goku\r\nLive as Goku. Fish, fly, eat, train, and battle your way through the DRAGON BALL Z sagas, making friends and building relationships with a massive cast of DRAGON BALL characters.', '2026-04-11 16:25:24', '2026-04-11 16:25:24'),
('018d937f-39a4-73cf-aae1-5556a2854277', 'Trepang2', 'Shooter', 170339, 'Trepang Studios', 'Team17 Digital Ltd, Team 17, Team17, Trepang Studios, Team 17 Digital Ltd, Team17 Digital, Team17 Digital Ltd.', 214, 1899, 93, 7, 'https://assets.isthereanydeal.com/018d937f-39a4-73cf-aae1-5556a2854277/banner300.jpg?t=1765818014', '2022-06-21 00:00:00', 'Become the ultimate badass in Trepang2: A gory, action-packed FPS set in the distant future. Unleash all hell on your enemies, dodge bullets and leave a trail of destruction in this hardcore and frenetic shooter.\n\nYou play as an escaped soldier, who has no memories of their past life, but is infused with supernatural abilities. Revenge is on your mind, and you\'ll stop at nothing to get what you want. Deliver devastating punches, sneak around in the shadows, wield explosive weapons, and give the bad guys a taste of their own medicine.', '2026-04-11 16:23:36', '2026-04-11 16:23:36'),
('018d937f-39fc-701c-8329-a4d4e9f8abff', 'Sayonara Wild Hearts', 'Great Soundtrack', 168645, 'Simogo', 'Annapurna Interactive, Annapurna Games', 7, 154, 96, 4, 'https://assets.isthereanydeal.com/018d937f-39fc-701c-8329-a4d4e9f8abff/banner300.jpg?t=1761153958', '2019-12-12 00:00:00', 'Sayonara Wild Hearts is a dreamy arcade game about riding motorcycles, skateboarding, dance battling, shooting lasers, wielding swords, and breaking hearts at 200 mph. As the heart of a young woman breaks, the balance of the universe is disturbed. A diamond butterfly appears in her dreams and leads her through a highway in the sky, where she finds her other self: the masked biker called The Fool. Journey through a custom-written pop soundtrack, chase scores, and set out to find the harmony of the universe, hidden away in the hearts of Little Death and her star-crossed allies: Dancing Devils, Howling Moons, Stereo Lovers and Hermit 64.', '2026-04-11 16:25:09', '2026-04-11 16:25:09'),
('018d937f-3a11-70d1-81cd-cac58ba1e391', 'Shadow of the Tomb Raider - Definitive Edition', 'Adventure', 148800, 'Eidos Montreal, Crystal Dynamics, Feral Interactive (Mac), Feral Interactive (Linux), Nixxes, Eidos-Montréal, Crystal Dynamics, Feral Interactive, Eidos-Montréal, Nixxes, Eidos-Montréal, Crystal Dynamics, Nixxes, Eidos-Montréal, Crystal Dynamics, Nixxes Software, Eidos-Montréal / Crystal Dynamics / Nixxies, Nixxes Software, EidosMontréal', 'Crystal Dynamics, Aspyr Media Inc, Aspyr Media, Inc., Aspyr, Square Enix [Nexway], Feral Interactive (Mac), Feral Interactive (Linux), Square Enix, Eidos Interactive Corp', 2023, 38171, 84, 16, 'https://assets.isthereanydeal.com/018d937f-3a11-70d1-81cd-cac58ba1e391/banner300.jpg?t=1765257009', '2018-09-14 00:00:00', 'As Lara Croft races to save the world from a Maya apocalypse, she must become the Tomb Raider she is destined to be.', '2026-04-11 16:22:45', '2026-04-11 16:22:45'),
('018d937f-3a3b-7210-bd2d-0d1dfb1d84c0', 'Red Dead Redemption 2', 'Open World', 879000, 'Rockstar Games', 'Rockstar Games, TAKE-TWO INTERACTIVE', 53003, 99993, 92, 8, 'https://assets.isthereanydeal.com/018d937f-3a3b-7210-bd2d-0d1dfb1d84c0/banner300.jpg?t=1760981447', '2019-11-05 00:00:00', 'Developed by the creators of Grand Theft Auto V and Red Dead Redemption, Red Dead Redemption 2 is an epic tale of life in America’s unforgiving heartland. The game’s vast and atmospheric world also provides the foundation for a brand new online multiplayer experience. America, 1899. The end of the Wild West era has begun. After a robbery goes badly wrong in the western town of Blackwater, Arthur Morgan and the Van der Linde gang are forced to flee. With federal agents and the best bounty hunters in the nation massing on their heels, the gang has to rob, steal and fight their way across the rugged heartland of America in order to survive. As deepening internal fissures threaten to tear the gang apart, Arthur must make a choice between his own ideals and loyalty to the gang that raised him. [Rockstar]', '2026-04-11 16:21:30', '2026-04-11 16:21:30'),
('018d937f-4263-733b-b061-5d1945668bdd', 'Yakuza: Like a Dragon', 'RPG', 0, 'Ryu Ga Gotoku Studio', 'SEGA, Ryu Ga Gotoku Studio', 912, 9506, 94, 6, 'https://assets.isthereanydeal.com/018d937f-4263-733b-b061-5d1945668bdd/banner300.jpg?t=1763644509', '2020-11-10 00:00:00', 'RISE LIKE A DRAGON. Become Ichiban Kasuga, a low-ranking yakuza grunt left on the brink of death by the man he trusted most. Take up your legendary bat and get ready to crack some underworld skulls in dynamic RPG combat set against the backdrop of modern-day Japan.', '2026-04-11 16:23:18', '2026-04-11 16:23:18'),
('018d937f-4382-707a-85b5-cdf1984ea8a8', 'Persona 4 Golden', 'JRPG', 338815, 'ATLUS, ATLUS Games', 'SEGA, ATLUS', 1248, 29340, 97, 3, 'https://assets.isthereanydeal.com/018d937f-4382-707a-85b5-cdf1984ea8a8/banner300.jpg?t=1763532028', '2020-06-14 00:00:00', 'Persona 4: The Golden is a remastered version of PS2 classic Shin Megami Tensei: Persona 4.', '2026-04-11 16:23:41', '2026-04-11 16:23:41'),
('018d937f-43f3-7181-a7ef-f059395e87bc', 'Manor Lords', 'Strategy', 440510, 'Slavic Magic', 'Hooded Horse, Hooded Horse Inc., Slavic Magic', 5778, 173178, 85, 15, 'https://assets.isthereanydeal.com/018d937f-43f3-7181-a7ef-f059395e87bc/banner300.jpg?t=1775770514', '2023-10-26 00:00:00', NULL, '2026-04-11 16:24:41', '2026-04-11 16:24:41'),
('018d937f-4443-7255-babb-a2a154f84dd0', 'Warhammer 40,000: Darktide', 'Horror', 199800, 'Fatshark', 'Fatshark', 7172, 107165, 71, 29, 'https://assets.isthereanydeal.com/018d937f-4443-7255-babb-a2a154f84dd0/banner300.jpg?t=1775524814', '2022-10-20 00:00:00', 'Fight together with your friends against hordes of enemies in this new Warhammer 40,000 experience. From the developers of the best-selling and award-winning co-op action franchise Vermintide, Warhammer 40,000: Darktide is a visceral 4-player co-op action game set in the hive city of Tertium. In the depths of the hive, the seeds of corruption threaten an overwhelming tide of darkness. A heretical cult known as the Admonition seeks to seize control of the planet Atoma Prime and lay waste to its inhabitants. It is up to you and your allies in the Inquisition to root out the enemy before the city succumbs to Chaos.', '2026-04-11 16:22:47', '2026-04-11 16:22:47'),
('018d937f-479c-72b8-a632-a3fda1f30d42', 'The Invincible', 'Adventure', 200848, 'Starward Industries', '11 bit studios, 11 Bit Studios SA', 54, 1193, 88, 12, 'https://assets.isthereanydeal.com/018d937f-479c-72b8-a632-a3fda1f30d42/banner300.jpg?t=1765237511', '2023-11-06 00:00:00', 'The Invincible is a first-person Sci-Fi thriller set in a retro-future timeline. Waking up as a space scientist on a hostile planet, you embark on a mysterious mission to find the missing crew of your spaceship. Survival is a matter of your correct choices, taken whilst uncovering the secrets of the planet, bigger than anyone thought.\r\n\r\nYou are a scientist onboard an interstellar scientific expedition, suddenly thrown into a life-or-death rescue mission. Landing on a planet Regis III you have to find the missing crew members using some advanced space equipment, whilst relying on your brains and instincts to survive on the planet which quickly occurs to be unwelcoming. Soon you\'ll discover that Regis III holds terrifying secrets which are uncovered while you\'re piecing together the fate of your crew. And as you delve deeper into the mystery, you realise that perhaps you are not alone, and that some places like this planet are better left untouched. But it\'s too late to turn back.\r\n\r\nFeatures:\r\n\r\n* Retro-future atompunk setting reminiscent of the space race\r\n* Analogue yet very advanced technology allowing for drones and autonomous robots to support or spoil your mission\r\n* Immersive gameplay with a non-linear story shaped by your relationships, choices and persuasive skills\r\n* Beautiful, state of the art graphics powered by Unreal Engine\r\n* Intriguing story inspired by Stanislaw Lem\'s seminal sci-fi cult classic of the same name', '2026-04-11 16:22:55', '2026-04-11 16:22:55'),
('018d937f-47a2-7353-9fbe-ec25ec289062', 'Terra Invicta', 'Strategy', 177620, 'Pavonis Interactive', 'Hooded Horse, Pavonis Interactive', 1292, 9584, 80, 20, 'https://assets.isthereanydeal.com/018d937f-47a2-7353-9fbe-ec25ec289062/banner300.jpg?t=1775769636', '2022-09-26 00:00:00', 'An extraterrestrial probe is detected approaching Earth. Unknown to humanity, an alien force has arrived in the far reaches of the icy Kuiper Belt and has begun mining a dwarf planet to prepare for an invasion.\n\nWith Earth\'s nations unable to unite to address the alien arrival, transnational groups of like-minded political, military and scientific leaders develop covert channels to coordinate a response. With the aliens\' motives uncertain, factions emerge, driven by hope, fear or greed.\n\nFrom the creators of Long War, an alien invasion has fractured humanity into seven ideological factions each with a unique vision for the future. Lead your chosen faction to take control of Earth\'s nations, expand across the Solar System, and battle enemy fleets in tactical combat.', '2026-04-11 16:23:23', '2026-04-11 16:23:23'),
('018d937f-4af2-718f-9dfb-c80328b245fe', 'Darkest Dungeon® II', 'Turn-Based Tactics', 96100, 'Red Hook Studios', 'Red Hook Studios', 1361, 22937, 75, 25, 'https://assets.isthereanydeal.com/018d937f-4af2-718f-9dfb-c80328b245fe/banner300.jpg?t=1760976345', '2021-10-26 00:00:00', 'Darkest Dungeon II is a roguelike road trip of the damned. Form a party, equip your stagecoach, and set off across a decaying landscape in a last gasp attempt to avert the apocalypse. The greatest dangers you face, however, may come from within...', '2026-04-11 16:24:22', '2026-04-11 16:24:22'),
('018d937f-4c71-73cc-bb02-d19a70711629', 'GUILTY GEAR -STRIVE-', 'Fighting', 274450, 'Arc System Works', 'Arc System Works', 10843, 30354, 88, 12, 'https://assets.isthereanydeal.com/018d937f-4c71-73cc-bb02-d19a70711629/banner300.jpg?t=1775722825', '2021-06-11 00:00:00', '“Guilty Gear -Strive-“ is the latest entry in the Guilty Gear fighting game franchise. Created by Daisuke Ishiwatari and developed by Arc System Works, “Guilty Gear -Strive-“ upholds the series’ reputation for groundbreaking hybrid 2D/3D cell-shaded graphics and intense, rewarding gameplay. There is a fully voiced story mode diving deep into the Guilty Gear universe, new characters joining fan favorites, and robust rollback net code. The cutting-edge 2D/3D hybrid graphics pioneered in the Guilty Gear series have been raised to the next level in “Guilty Gear -Strive-“. The new artistic direction and improve character animations will go beyond anything you’ve seen before in a fighting game!\r\n\r\n◆New Revolution in Fighting Games!\r\nGuilty Gear -Strive- brings a number of new and innovative game play mechanics designed to allow players new to the series to quickly learn the fundamentals while maintaining the deep, creative gameplay Guilty Gear is praised for. New additions to the series such as a wall-breaking mechanic will allow for new and exciting approaches to battle.\r\n\r\n◆The fate of the universe will be determined…\r\nThe story of Guilty Gear, spanning over 20 years, will finally come to a conclusion in “Guilty Gear -Strive-“. The trials and tribulations of the series’ heroes and villains will finally be resolved. Discover the astonishing truth awaiting at the end of all things.', '2026-04-11 16:24:38', '2026-04-11 16:24:38'),
('018d937f-4c8c-713d-9e81-deafc79cc4ac', 'Neon White', 'FPS', 167289, 'Angel Matrix', 'Annapurna Games, Annapurna Interactive', 194, 3170, 98, 2, 'https://assets.isthereanydeal.com/018d937f-4c8c-713d-9e81-deafc79cc4ac/banner300.jpg?t=1760985010', '2022-06-16 00:00:00', 'Neon White is a lightning fast first-person action game about exterminating demons in Heaven. You are White, an assassin handpicked from Hell to compete with other demon slayers for a chance to live permanently in Heaven. The other assassins seem familiar, though… did you know them in a past life?\r\n\r\nFeatures:\r\n• You play as Neon White, an assassin plucked from Hell to compete with other demon slayers for a shot at redemption.\r\n• Collect “Soul Cards” to attack your foes or discard them to use unique movement abilities.\r\n• Compete for the best times by cleverly combining cards to discover massive shortcuts.\r\n• Uncover Heaven’s mysteries by getting to know the other assassins… did you know them in a past life?', '2026-04-11 16:22:01', '2026-04-11 16:22:01'),
('018d937f-4cb1-7067-9ee2-3c3366d2a96b', 'SIFU', 'Action', 131200, 'Sloclap', 'Kepler Interactive, Sloclap, Sloclap, Kepler Interactive, Kepler Interactive (Epic 80/20)', 1351, 3088, 92, 8, 'https://assets.isthereanydeal.com/018d937f-4cb1-7067-9ee2-3c3366d2a96b/banner300.jpg?t=1761585826', '2022-02-08 00:00:00', 'Sifu is a stylish yet gritty beat-em-up, featuring visceral hand-to-hand combat in a contemporary urban setting. From Sloclap, creators of acclaimed PS4 fighting game Absolver, Sifu follows a young kung fu student on a path of revenge, hunting for the murderers of his family. One against all, he has no allies and countless enemies. He will have to rely on his unique mastery of kung fu to prevail and preserve his family’s legacy.', '2026-04-11 16:23:46', '2026-04-11 16:23:46'),
('018d937f-4ce1-7187-8673-ca31f819a5fc', 'Scarlet Nexus', 'Anime', 131400, 'BANDAI NAMCO Studios, BANDAI NAMCO Studios Inc.', 'BANDAI NAMCO Entertainment, Bandai Namco Entertainment America Inc., Bandai Namco Entertainment Inc., Bandai Namco, Bandai Namco US, BANDAI NAMCO Studios Inc.', 162, 14318, 81, 19, 'https://assets.isthereanydeal.com/018d937f-4ce1-7187-8673-ca31f819a5fc/banner300.jpg?t=1761153627', '2021-06-24 00:00:00', 'Assume the role of Yuito Sumeragi, a new recruit to the OSF aiming to become an elite psionic like the one who saved him as a child. Armed with a talent in psycho-kinesis, explore the futuristic city of New Himuka and uncover the mysteries of a Brain Punk future caught between technology and psychic abilities in SCARLET NEXUS. Using psycho-kinetic abilities, the world around you becomes your greatest weapon. Lift, break and throw pieces of your environment to build your attack combos and lay waste to your enemies. Deranged mutants that descended from the sky, highly resistant to conventional attack methods and defenses. Tormented by the constant pain of their mutation, they seek brains of living organisms to calm their madness. Explore and protect a futuristic Japanese landscape that combines inspirations from classic anime and western science fiction. Dive into a complex story of bonds, courage and heroism crafted by minds behind the iconic Tales of Vesperia.', '2026-04-11 16:24:59', '2026-04-11 16:24:59'),
('018d937f-4d2d-7144-8fb4-b010a092e21e', 'Thymesia', 'Souls-like', 423561, 'OverBorder Studio', 'Team17 Digital Ltd, Team 17, Team17, OverBorder Studio, Team 17 Digital Ltd, Team17 Digital, Team17 Digital Ltd.', 32, 3128, 83, 17, 'https://assets.isthereanydeal.com/018d937f-4d2d-7144-8fb4-b010a092e21e/banner300.jpg?t=1761610904', '2022-08-18 00:00:00', 'Thymesia is a gruelling action-RPG with fast-paced combat and an intricate plague weapon system. In a kingdom where death spreads, play as a mysterious character known by the code name \"Corvus\". Prey upon your enemies, wield the power of disease and find the truth in your own memories.', '2026-04-11 16:24:51', '2026-04-11 16:24:51'),
('018d937f-4ec1-7046-a86c-1ee15a9a4349', 'Potion Craft: Alchemist Simulator', 'Crafting', 338815, 'niceplay games', 'tinyBuild, tinyBuild LLC, tinyBuild Games', 1128, 9540, 92, 8, 'https://assets.isthereanydeal.com/018d937f-4ec1-7046-a86c-1ee15a9a4349/banner300.jpg?t=1775228719', '2021-09-21 00:00:00', 'Potion Craft is an alchemist simulator where you physically interact with your tools and ingredients to brew potions. You\'re in full control of the whole shop: invent new recipes, attract customers and experiment to your heart\'s content. Just remember: the whole town is counting on you. \n\nEvery day customers will come to your store looking for solutions to their problems. You will face consequences depending on what you decide to sell them. Attract guilds, befriend notable figures (or feud with them), gain riches and influence - and one day, you may even decide the fate of the whole town.', '2026-04-11 16:23:44', '2026-04-11 16:23:44'),
('018d937f-502d-707c-b964-11cd6990ba4f', 'V Rising', 'Survival', 508307, 'Stunlock Studios', 'Stunlock Studios, Stunlock Studios AB', 6556, 146446, 89, 11, 'https://assets.isthereanydeal.com/018d937f-502d-707c-b964-11cd6990ba4f/banner300.jpg?t=1773096607', '2022-05-17 00:00:00', 'Awaken as a weakened vampire after centuries of slumber. Hunt for blood to regain your strength while hiding from the scorching sun to survive. Rebuild your castle and convert humans into your loyal servants in a quest to raise your vampire empire. Make allies or enemies online or play solo offline, fend off holy soldiers, and wage war in a world of conflict.\n\nWill you become the next Dracula?', '2026-04-11 16:22:29', '2026-04-11 16:22:29'),
('018d937f-50e4-73f6-8537-28c670908187', 'Tiny Tina\'s Wonderlands', 'Loot', 1016783, 'Gearbox Software', '2K, 2K Games, TAKE-TWO INTERACTIVE, Gearbox Software', 668, 14063, 70, 30, 'https://assets.isthereanydeal.com/018d937f-50e4-73f6-8537-28c670908187/banner300.jpg?t=1760981116', '2022-03-25 00:00:00', 'Embark on an epic adventure full of whimsy, wonder, and high-powered weaponry! Bullets, magic, and broadswords collide across this chaotic fantasy world brought to life by the unpredictable Tiny Tina, who makes the rules, changes the world on the fly, and guides players on their journey. Customize your own multiclass hero and loot, shoot, slash, and cast your way through outlandish monsters and treasure-filled dungeons on a quest to stop the tyrannical Dragon Lord. Everyone\'s welcome, so join the party, throw on your adventuring boots, and be Chaotic Great!', '2026-04-11 16:25:27', '2026-04-11 16:25:27'),
('018d937f-51d0-71f8-bae2-7721999c5f3d', 'IXION', 'Space', 162543, 'Bulwark Studios', 'Kasedo Games, Kasedo Games Ltd, Kalypso Media Digital Ltd (Kasedo Games), SEGA', 320, 17059, 77, 23, 'https://assets.isthereanydeal.com/018d937f-51d0-71f8-bae2-7721999c5f3d/banner300.jpg?t=1760030419', '2022-12-07 00:00:00', 'IXION combines city building, survival elements and exploration, into a thrilling space opera as you explore the stars. Propelled onwards through a perilous journey, you are the Administrator of the Tiqqun space station, charged with finding a new home for humanity.\n\nKeeping the station sound and flying will require a deft hand and strategic thinking, as you are constantly pulled between maintaining hull integrity, bringing in new resources and managing power consumption.\n\nWhat choices will you make when confronted with impending disaster? What will you discover out there in the dark?', '2026-04-11 16:22:11', '2026-04-11 16:22:11');
INSERT INTO `game` (`id_game`, `nama_game`, `genre`, `harga_sekarang`, `developer`, `publisher`, `current_player`, `peak_player`, `good_review`, `bad_review`, `url_gambar`, `tanggal_rilis`, `deskripsi`, `created_at`, `updated_at`) VALUES
('018d937f-51e3-701c-982b-d63346c12655', 'Cairn', 'Stylized', 432035, 'The Game Bakers', 'The Game Bakers, Plug-in Digital, Plug In Digital', 1086, 14996, 94, 6, 'https://assets.isthereanydeal.com/018d937f-51e3-701c-982b-d63346c12655/banner300.jpg?t=1770987906', '2026-01-29 00:00:00', 'Reach a summit never climbed before in this survival-climber from the creators of Furi and Haven. \r\n\r\nAs pro climber Aava, you embark on the ascent of Mount Kami, a summit that has never been reached. Along the journey, meet unexpected companions and hear from those left on the ground. Discover the mountain\'s history and decide what Aava is willing to sacrifice to achieve her dream.\r\n\r\nExplore the mountain, read the rock face from the ground and plan your route carefully to reach the top. Solve problems while on the wall to navigate difficult sections. You can climb on anything, so choose your path wisely!', '2026-04-11 16:25:04', '2026-04-11 16:25:04'),
('018d937f-51f4-727c-95c0-ba550d156c86', 'Disco Elysium - The Final Cut', 'RPG', 42499, 'ZA/UM, Disco Elysium UK Ltd', 'ZA/UM, Disco Elysium UK Ltd, Disco Elysium', 2071, 8081, 92, 8, 'https://assets.isthereanydeal.com/018d937f-51f4-727c-95c0-ba550d156c86/banner300.jpg?t=1771867829', '2019-10-14 00:00:00', 'Disco Elysium - The Final Cut is the definitive edition of the smash-hit RPG. Pursue your political dreams in new quests, meet and question more of the city\'s locals, and explore a whole extra area. Full voice-acting, controller support, and expanded language options also included. Get even more out of this award-winning open world. You\'re a detective with a unique skill system at your disposal and a whole city block to carve your path across. Interrogate unforgettable characters, crack murders, or take bribes. Become a hero or an absolute disaster of a human being.', '2026-04-11 16:22:24', '2026-04-11 16:22:24'),
('018d937f-5288-7397-8712-586d47b31fab', 'Dredge', 'Exploration', 82799, 'Black Salt Games', 'Team17 Digital Ltd, Team 17, Team17, Black Salt Games, Team 17 Digital Ltd, Team17 Digital, Team17 Digital Ltd.', 666, 12652, 95, 5, 'https://assets.isthereanydeal.com/018d937f-5288-7397-8712-586d47b31fab/banner300.jpg?t=1766055015', '2023-03-29 00:00:00', 'Dredge is a fishing adventure with a sinister undercurrent. Sell your catch, upgrade your vessel and dredge the depths for long-buried relics. Explore the stories of the strange locals and discover why some things are best left forgotten. \r\n\r\nStarting from your new home in a group of islands known as The Marrows, upgrade your engines and set sail for the neighboring regions - each with their own unique fish, personalities and secrets.\r\nDredge up forgotten treasures. Outsmart unremembered terrors.\r\n\r\nSomeone wants very badly to retrieve relics lost to the ocean floor. The work is lucrative, but can you trust them? What will they use the relics for? And will they ever be satisfied?\r\n\r\nIt\'s not just the sharp rocks and shallow reefs you need to watch out for - keep your eyes on the depths below and the sky above. The biggest threat to your safety might come from within.', '2026-04-11 16:21:43', '2026-04-11 16:21:43'),
('018d937f-53ee-71c1-9635-7035894410d7', 'Frostpunk 2', 'City Builder', 293052, '11 bit studios, 11 Bit Studios SA', '11 bit studios, 11 Bit Studios SA', 2225, 35533, 74, 26, 'https://assets.isthereanydeal.com/018d937f-53ee-71c1-9635-7035894410d7/banner300.jpg?t=1775725515', '2024-09-07 00:00:00', 'Frostpunk 2 is the sequel to the highly acclaimed, BAFTA-nominated society survival game that blended city building, strategy and management gameplay, creating a brand new genre. Its successor takes place 30 years after the apocalyptic blizzard storm, and Earth is still overwhelmed by the icy climate of neverending frost and harsh weather.\r\n\r\nDemands and expectations of various factions will raise tensions and evoke conflicts, but will a cold-blooded rule and a Machiavellian approach to politics be necessary? As the everlasting cold continues its grip on the city and outside threats arise, you\'ll need to make sure your people are united, driven, and ready for difficult, unavoidable sacrifices!', '2026-04-11 16:22:35', '2026-04-11 16:22:35'),
('018d937f-590c-728b-ac35-38bcff85f086', 'Elden Ring', 'Souls-like', 762545, 'From Software, FromSoftware Inc., FromSoftware, Inc.', 'BANDAI NAMCO Entertainment, Bandai Namco, BANDAI NAMCO Entertainment US, FromSoftware, Inc., Bandai Namco Entertainment, Bandai Namco Entertainment Inc., Bandai Namco US, FromSoftware, Inc., FromSoftware', 46913, 940453, 93, 7, 'https://assets.isthereanydeal.com/018d937f-590c-728b-ac35-38bcff85f086/banner300.jpg?t=1767885314', '2022-02-25 00:00:00', 'A New World Created By Hidetaka Miyazaki And George R. R. Martin. ELDEN RING, developed by FromSoftware, Inc. and BANDAI NAMCO Entertainment Inc., is a fantasy action-RPG adventure set within a world created by Hidetaka Miyazaki creator of the influential DARK SOULS video game series; and George R.R. Martin author of The New York Times best-selling fantasy series, A Song of Ice and Fire. Danger and discovery lurk around every corner in FromSoftware\'s largest game to-date.  Hidetaka Miyazaki, President and Game Director of FromSoftware Inc. Known for directing critically-acclaimed games in beloved franchises including Armored Core, Dark Souls, and Sekiro: Shadows Die Twice.  George R.R. Martin is the #1 New York Times bestselling author of many novels, including the acclaimed series A Song of Ice and Fire - A Game of Thrones, A Clash of Kings, A Storm of Swords, A Feast For Crows, and A Dance with Dragons. As a writer-producer, he has worked on The Twilight Zone, Beauty and the Beast, and various feature films and pilots that were never made.', '2026-04-11 16:23:08', '2026-04-11 16:23:08'),
('018d937f-5ccf-7344-a579-d8feb6ba83cf', 'Cult of the Lamb', 'Base Building', 230000, 'Massive Monster', 'Devolver Digital', 4738, 60610, 95, 5, 'https://assets.isthereanydeal.com/018d937f-5ccf-7344-a579-d8feb6ba83cf/banner300.jpg?t=1769837716', '2022-08-11 00:00:00', 'Start your own cult in a land of false prophets, venturing out into diverse and mysterious regions to build a loyal community of woodland worshippers and spread your Word to become the one true cult. BUILD YOUR FLOCK. Collect and use resources to build new structures, perform dark rituals to appease the gods, and give sermons to reinforce the faith of your flock. DESTROY THE NON-BELIEVERS. Explore a sprawling, randomly generated world, fight off hordes of enemies and defeat rival cult leaders in order to absorb their power and assert your cult\'s dominance. SPREAD YOUR WORD. Train your flock and embark on a quest to explore and discover the secrets of five mysterious regions. Cleanse the non-believers, spread enlightenment and perform mystical rituals on the journey to become the mighty lamb god.', '2026-04-11 16:25:17', '2026-04-11 16:25:17'),
('018d937f-5dbf-705c-b6b1-19bd76e2d45a', 'Spiritfarer: Farewell Edition', 'Emotional', 74270, 'Thunder Lotus Games, Thunder Lotus', 'Plug In Digital, Plugin Digital, Thunder Lotus Games, Plug-in Digital, Thunder Lotus', 1034, 11521, 95, 5, 'https://assets.isthereanydeal.com/018d937f-5dbf-705c-b6b1-19bd76e2d45a/banner300.jpg?t=1761606031', '2020-08-18 00:00:00', NULL, '2026-04-11 16:24:46', '2026-04-11 16:24:46'),
('018d937f-6136-71e4-a7d4-088a32c7d518', 'The Alters', 'Survival', 385594, '11 bit studios, 11 Bit Studios SA', '11 bit studios, 11 Bit Studios SA', 497, 18120, 90, 10, 'https://assets.isthereanydeal.com/018d937f-6136-71e4-a7d4-088a32c7d518/banner300.jpg?t=1774966812', '2025-06-13 00:00:00', 'The Alters is an ambitious sci-fi survival game with a unique twist. You play as Jan Dolski, the lone survivor of a crash-landed expedition on a hostile planet. To survive, you must form a new crew for your mobile base. Using a substance called Rapidium, you create alternative versions of Jan—THE ALTERS—each one shaped by a different crucial decision from the protagonist’s past.\r\n\r\nAs you navigate through survival and moral dilemmas, you will explore a branching narrative filled with captivating character dynamics and challenging decisions.', '2026-04-11 16:21:28', '2026-04-11 16:21:28'),
('018d937f-6144-7057-ad1c-0e99a3a71797', 'Hogwarts Legacy', 'Magic', 920000, 'Avalanche Software', 'Warner Games Inc., Warner Bros. Games Inc., Warner Bros. Games, Warner, Warner Bros Interactive Entertainment, Portkey Games, Warner Bros. Interactive Entertainment, Microsoft, Xbox', 9903, 850885, 90, 10, 'https://assets.isthereanydeal.com/018d937f-6144-7057-ad1c-0e99a3a71797/banner300.jpg?t=1773933608', '2023-02-04 00:00:00', 'LIVE THE UNWRITTEN = Hogwarts Legacy is an immersive, open-world action RPG set in the world first introduced in the Harry Potter books. Now you can take control of the action and be at the center of your own adventure in the wizarding world. Embark on a journey through familiar and new locations as you explore and discover fantastic beasts, customize your character and craft potions, master spell casting, upgrade talents, and become the wizard you want to be.\r\n\r\nExperience Hogwarts in the 1800s. Your character is a student who holds the key to an ancient secret that threatens to tear the wizarding world apart. You have received a late acceptance to the Hogwarts School of Witchcraft and Wizardry and soon discover that you are no ordinary student: you possess an unusual ability to perceive and master Ancient Magic. Only you can decide if you will protect this secret for the good of all, or yield to the temptation of more sinister magic.\r\n\r\nDiscover the feeling of living at Hogwarts as you make allies, battle Dark wizards, and ultimately decide the fate of the wizarding world. Your legacy is what you make of it.', '2026-04-11 16:24:56', '2026-04-11 16:24:56'),
('018d937f-63a5-7158-a9fb-50a7a6787746', 'COCOON', 'Adventure', 99999, 'Geometric Interactive', 'Annapurna Games, Annapurna Interactive', 37, 384, 94, 6, 'https://assets.isthereanydeal.com/018d937f-63a5-7158-a9fb-50a7a6787746/banner300.jpg?t=1763732412', '2023-09-29 00:00:00', 'From Jeppe Carlsen, the lead gameplay designer of LIMBO and INSIDE - COCOON takes you on an adventure across worlds within worlds. Master world-leaping mechanics to unravel a cosmic mystery.\r\n\r\nCOCOON is a unique take on the puzzle adventure genre, where each world exists within an orb that you can carry on your back. Wrap your head around the core mechanic of leaping between worlds - and combine, manipulate, and rearrange them to solve intricate puzzles\r\n\r\nInteract with alien environments and biomechanical devices left behind by an ancient civilization. Journey through unique and diverse biomes, from industrial structures to massive organic caverns, and discover how they are connected to one another.', '2026-04-11 16:23:49', '2026-04-11 16:23:49'),
('018d937f-664b-722c-b762-126631fedaa6', 'Age of Empires IV: Anniversary Edition', 'Strategy', 271018, 'Relic Entertainment / World\'s Edge, Relic Entertainment, Climax Studios, Forgotten Empires, World\'s Edge', 'Xbox Game Studios, Microsoft, Relic Entertainment, World\'s Edge, Xbox', 16525, 73629, 86, 14, 'https://assets.isthereanydeal.com/018d937f-664b-722c-b762-126631fedaa6/banner300.jpg?t=1775144104', '2021-10-28 00:00:00', 'Celebrating its first year of delighting millions of global players, the award-winning and best-selling strategy franchise continues with Age of Empires IV: Anniversary Edition, putting you at the center of even more epic historical battles that shaped the world. Featuring both familiar and innovative new ways to expand your empire in vast landscapes with stunning 4K visual fidelity, Age of Empires IV: Anniversary Edition brings an evolved real-time strategy game to the next level in this celebratory new version that includes a host of free new content such as brand-new civilizations, new maps, additional in-game updates and languages, and new masteries, challenges, taunts and cheats – all at an amazing value that packs in more history than ever before! \r\n\r\n\r\n\r\nTwo New Civilizations, 8 New Maps - Lead the mighty Malians of West Africa as one of the richest trading nations of all-time as you focus on strong economic prowess in mining and investing in gold. \r\n\r\n\r\n\r\nOr assemble one of the longest lasting empires in history with the Ottoman civilization and its well-trained military force, which features the largest gunpowder siege weapons available – the Great Bombards – mighty cannons that can fell any opponents who stand in your way. \r\n\r\n\r\n\r\nCustomize Your Game with Mods (Beta) - Chart your own course with powerful creator tools in the latest beta release of Mod Editor. Sculpt your own skirmish and multiplayer maps, craft unique mission scenarios, forge data driven tuning packs and envision new modes of play for Age of Empires IV.\r\n\r\n\r\n\r\nReturn to History – The past is prologue as you are immersed in a rich historical setting of 10 diverse civilizations across the world from the English to the Chinese to the Delhi Sultanate in your quest for victory. Build cities, manage resources, and lead your troops to battle on land and at sea in 4 distinct campaigns with 35 missions that span across 500 years of history from the Dark Ages up to the Renaissance.\r\n\r\n\r\n\r\nAn Age for All Players – Age of Empires IV is an inviting experience for new players with a tutorial system that teaches the essence of real-time strategy and a Campaign Story Mode designed for first time players to help achieve easy setup and success, yet is challenging enough for veteran players with new game mechanics, evolved strategies, and combat techniques.\r\n\r\n\r\n\r\nChallenge the World – Jump online to compete, cooperate or spectate with up to 7 of your friends in PVP and PVE multiplayer modes that include ranked seasons and much more! \r\n\r\n\r\n\r\nChoose Your Path to Greatness with Historical Figures – Live the adventures of Joan of Arc in her quest to defeat the English, or command mighty Mongol troops as Genghis Khan in his conquest across Asia. The choice is yours – and every decision you make will determine the outcome of history.', '2026-04-11 16:22:27', '2026-04-11 16:22:27'),
('018d937f-677c-7197-9877-b255219f126e', 'Starship Troopers: Extermination', 'Online Co-Op', 176400, 'Offworld Industries Ltd, Offworld Industries Ltd., Offworld', 'Offworld Industries, Offworld, Offworld Industries Ltd.', 521, 15209, 80, 20, 'https://assets.isthereanydeal.com/018d937f-677c-7197-9877-b255219f126e/banner300.jpg?t=1774628404', '2023-05-18 00:00:00', 'Starship Troopers: Extermination is a 16 player co-op FPS that puts you on the far-off front lines of an all-out battle against the Bugs! Squad up, grab your rifle, and do your part as an elite Deep Space Vanguard Trooper set to take back planets claimed by the Arachnid threat!', '2026-04-11 16:24:43', '2026-04-11 16:24:43'),
('018d937f-694e-707e-aa51-e9230816771b', 'Viewfinder', 'Puzzle Platformer', 132214, 'Sad Owl Studios', 'Thunderful Publishing, Thunderful Games, Thunderful Publishing AB', 98, 2018, 94, 6, 'https://assets.isthereanydeal.com/018d937f-694e-707e-aa51-e9230816771b/banner300.jpg?t=1764844523', '2023-07-18 00:00:00', 'Challenge perception, redefine reality, and reshape the world around you with an instant camera. Viewfinder is a new single player game offering gamers hours of interesting and fun experiences while uncovering the mysteries left behind.\r\n\r\nAbout the game\r\n\r\nViewfinder is a mind-bending first person adventure game in which you can bring pictures to life by placing them into the world.\r\n\r\n• Reshape Reality. Beyond photographs, bring paintings, sketches, screenshots and postcards to life while reshaping the world\r\n\r\n• Exploration is learning, the player will learn the secrets of the world, the reason why it exists, and the freedom to create. Explore multiple hub worlds that are all cohesive and encompass similar, but complex, differences.\r\n\r\n• Experience as much as you want. Viewfinder’s Narrative is player driven and will be an approachable experience to someone who just wants to play and solve puzzles, and a rich well thought off world to a player who wants to learn more.\r\n\r\n• Find the answer to the impossible, once you step in the world of Viewfinder.', '2026-04-11 16:22:19', '2026-04-11 16:22:19'),
('018d937f-6b6f-711c-b807-77468cad7a62', 'The Thaumaturge', 'RPG', 234238, 'Fool\'s Theory', '11 bit studios, 11 Bit Studios SA', 151, 2751, 81, 19, 'https://assets.isthereanydeal.com/018d937f-6b6f-711c-b807-77468cad7a62/banner300.jpg?t=1765226114', '2024-03-04 00:00:00', 'The Thaumaturge is an isometric, story-rich RPG with a unique take on turn-based combat, character development features, and investigation mechanics, facing you with morally ambiguous choices set in a world teeming with mysterious powers and strange ethereal beings called Salutors.\r\n\r\nThe year is 1905. Warsaw lives under the yoke of imperial Russian tsardom. Its inhabitants constitute a diverse group of different ancestries, views, and beliefs with often conflicting interests: Russian soldiers, Jewish merchants, Polish townspeople, and more. Despite the circumstances, the city is a buzzing metropolis, where one can attend a breathtaking party with the high society, and later get robbed in one of the dark alleys of the Praga district. A city of great hopes and dreams on one hand and dark desires on the other.\r\n\r\nIn this world, a force that cannot be ignored are Thaumaturges individuals versed in taming spirit-like beings called Salutors, used for manipulation of the temperaments and affinities of other people and even ultimately in combat. The devil is in the detail - only Thaumaturges are fully aware of the Salutors\' nature and only they can perceive them in their true essence. Their capability to influence others significantly and demonstrably increases their ability to change the surrounding world - however, Thaumaturgy is a power that should be used with caution.', '2026-04-11 16:24:25', '2026-04-11 16:24:25'),
('018d937f-6d3c-7300-bd51-606452abc4e0', 'The Precinct', 'Crime', 207999, 'Fallen Tree Games Ltd, Fallen Tree Games', 'Kwalee, Kwalee Ltd', 226, 9738, 86, 14, 'https://assets.isthereanydeal.com/018d937f-6d3c-7300-bd51-606452abc4e0/banner300.jpg?t=1773950407', '2025-05-13 00:00:00', 'Averno City, 1983. Gangs rule the streets and your father lies restless in his grave. Clean up the city, uncover the truth, and embark on thrilling vehicle chases through destructible environments in this neon-noir action sandbox police game.\n\nYou are Officer Nick Cordell Jr. As a rookie beat cop fresh out of the Academy, you\'re on the front line of defence for Averno\'s citizens. Dive into a world of thrilling car chases, procedurally-generated crimes, and a healthy dose of 1980s noir as you protect the populace and solve the mystery of your father\'s murder in the line of duty.', '2026-04-11 16:24:30', '2026-04-11 16:24:30'),
('018d937f-6ed9-71ca-8010-4baa9771ef55', 'Warhammer 40,000: Space Marine 2', 'Warhammer 40K', 390000, 'Saber Interactive', 'Focus Entertainment, Focus Home Interactive', 17981, 225690, 83, 17, 'https://assets.isthereanydeal.com/018d937f-6ed9-71ca-8010-4baa9771ef55/banner300.jpg?t=1774548615', '2024-06-03 00:00:00', NULL, '2026-04-11 16:21:38', '2026-04-11 16:21:38'),
('018d937f-6ee2-70f6-940c-6212ac15c400', 'Dragon\'s Dogma 2', 'Open World', 1042206, 'Capcom Co., Ltd., Capcom, CAPCOM Co. Ltd.', 'Capcom Co., Ltd., Capcom Ltd, Capcom Japan Inc., Capcom, CAPCOM CO. LTD, Capcom (JP), Microsoft, Xbox', 2011, 228585, 61, 39, 'https://assets.isthereanydeal.com/018d937f-6ee2-70f6-940c-6212ac15c400/banner300.jpg?t=1768893022', '2024-03-22 00:00:00', 'The Dragon\'s Dogma series consists of action games in a fantasy setting where players adventure in an expansive open world of swords and magic.\r\n\r\nDragon\'s Dogma 2 is the latest title in the series, and the first mainline entry since the first Dragon\'s Dogma was released in 2012. The game is currently in production, and with a development environment that leverages Capcom\'s proprietary RE ENGINE it is sure to satisfy both newcomers as well as long-time fans.', '2026-04-11 16:21:51', '2026-04-11 16:21:51'),
('018d937f-6ee2-70f6-940c-6212ac74369e', 'Blasphemous 2', 'Combat', 115499, 'The Game Kitchen', 'Team17 Digital Ltd, Team 17, Team17, The Game Kitchen, Team 17 Digital Ltd, Team17 Digital, Team17 Digital Ltd.', 755, 8791, 90, 10, 'https://assets.isthereanydeal.com/018d937f-6ee2-70f6-940c-6212ac74369e/banner300.jpg?t=1774970421', '2023-08-24 00:00:00', 'The second scripture in the Blasphemous series portends the return of The Penitent One, with a story that continues from the free Wounds of Eventide DLC for the original game, where The Heart in the sky heralded the return of The Miracle and foretold the birth of a new miracle child.\r\n\r\nAwakened in a strange new land, and displaced from his final resting place, The Penitent One is thrust back into the endless cycle of life, death, and resurrection, with no other option than to explore this perilous new world and uncover its long-forgotten secrets.\r\n\r\nHordes of grotesque enemies stand in your way, awaiting final judgement by the brutal hand of the Penitent One, with titanic twisted bosses also lurking in the darkness, waiting for their chance to return you to the grave from whence you came.', '2026-04-11 16:22:17', '2026-04-11 16:22:17'),
('018d937f-6ee4-73f5-858c-2fde3c008587', 'Pacific Drive', 'Driving', 226800, 'Ironwood Studios', 'Kepler Interactive, Ironwood Studios, Kepler Interactive Limited', 445, 18507, 83, 17, 'https://assets.isthereanydeal.com/018d937f-6ee4-73f5-858c-2fde3c008587/banner300.jpg?t=1767987315', '2024-02-22 00:00:00', 'Pacific Drive is a first-person driving survival game set in the pacific northwest region of the United States. With your car as your only companion, you\'ll travel deep into the Olympic Exclusion Zone - a surreal and mysterious place that\'s been abandoned for decades.', '2026-04-11 16:25:19', '2026-04-11 16:25:19'),
('018d937f-6ee8-7321-a387-d87af065f568', 'ARC Raiders', 'Extraction Shooter', 370546, 'Embark Studios', 'Embark Studios, Embark Studios AB, Nexon', 99225, 481966, 86, 14, 'https://assets.isthereanydeal.com/018d937f-6ee8-7321-a387-d87af065f568/banner300.jpg?t=1775150414', '2025-10-30 00:00:00', 'ARC Raiders is a cooperative third-person shooter where you and your squad of Raiders unite to resist the onslaught of ARC - a ruthless, mechanized threat descending from space.\n\nYou play as one of the Raiders, a rogue group of resistance fighters. With the help of a patchwork early warning system, you fight to protect our home against enemies dropping from orbit. \n\nScavenge the ruins of the past. Wield tools and gadgets to outsmart the enemy. Use on-the-fly tactics, your surroundings, and physics to your advantage. If you and your squad play well together, one day the stars may again become beacons of hope, instead of omens of oblivion.', '2026-04-11 16:22:09', '2026-04-11 16:22:09'),
('018d937f-7466-727c-8331-8f9c8c2af33b', 'Persona 3 Reload', 'JRPG', 579000, 'ATLUS, ATLUS Games', 'SEGA, ATLUS, Microsoft, Xbox', 3850, 43995, 94, 6, 'https://assets.isthereanydeal.com/018d937f-7466-727c-8331-8f9c8c2af33b/banner300.jpg?t=1764778811', '2023-08-23 00:00:00', 'Your story begins again. Memento Mori. \r\n\r\nAwaken the depths of your heart in Persona 3 Reload, the genre-defining RPG now reborn for modern consoles.', '2026-04-11 16:23:16', '2026-04-11 16:23:16'),
('018d937f-74c1-708e-8193-97dfbe6a98fe', 'Resident Evil 4 (2023)', 'Horror', 572883, 'Capcom Co., Ltd., Capcom, CAPCOM Co. Ltd.', 'Capcom Co., Ltd., Capcom Japan Inc., Capcom Ltd, Capcom, CAPCOM CO. LTD, Capcom (JP)', 33571, 168097, 97, 3, 'https://assets.isthereanydeal.com/018d937f-74c1-708e-8193-97dfbe6a98fe/banner300.jpg?t=1772503528', '2023-03-24 00:00:00', NULL, '2026-04-11 16:23:34', '2026-04-11 16:23:34'),
('018d937f-781e-716d-acee-7650541ad533', 'RESIDENT EVIL 2 (2019)', 'Zombies', 677799, 'Capcom Co., Ltd., Capcom, CAPCOM Co. Ltd.', 'Capcom Co., Ltd., Capcom, Capcom Japan Inc., Capcom Ltd, CAPCOM CO. LTD, Capcom (JP), Tiger Electronics', 14406, 74194, 97, 3, 'https://assets.isthereanydeal.com/018d937f-781e-716d-acee-7650541ad533/banner300.jpg?t=1769055907', '2019-01-25 00:00:00', NULL, '2026-04-11 16:23:21', '2026-04-11 16:23:21'),
('018d937f-799e-72ce-893c-4a824dcc7a46', 'Remnant II', 'Souls-like', 203221, 'Gunfire Games', 'Arc Games, Gearbox Publishing San Francisco, THQ Nordic GmbH, THQ Nordic, 680', 2888, 109327, 83, 17, 'https://assets.isthereanydeal.com/018d937f-799e-72ce-893c-4a824dcc7a46/banner300.jpg?t=1764662710', '2023-07-25 00:00:00', 'Remnant II is the sequel to the best-selling game Remnant: From the Ashes that pits survivors of humanity against new deadly creatures and god-like bosses across terrifying worlds. Play solo or co-op with two other friends to explore the depths of the unknown to stop an evil from destroying reality itself. To succeed, players will need to rely on their own skills and those of their team to overcome the toughest challenges and to stave off humanity\'s extinction.', '2026-04-11 16:23:00', '2026-04-11 16:23:00'),
('018d937f-7a06-7082-ae40-6a37d855cb32', 'Monster Hunter Wilds', 'Hunting', 1002715, 'Capcom Co., Ltd., Capcom, CAPCOM Co. Ltd.', 'Capcom Co., Ltd., Capcom, Capcom Ltd, CAPCOM CO. LTD, Capcom (JP)', 26668, 1384608, 51, 49, 'https://assets.isthereanydeal.com/018d937f-7a06-7082-ae40-6a37d855cb32/banner300.jpg?t=1771383033', '2025-02-28 00:00:00', 'The unbridled force of nature runs wild and relentless, with environments transforming drastically from one moment to the next. This is a story of monsters and humans and their struggles to live in harmony in a world of duality. Fulfill your duty as a Hunter by tracking and defeating powerful monsters and forging strong new weapons and armor from the materials you harvest from your hunt as you uncover the connection between the people of the Forbidden Lands and the locales they inhabit. The ultimate hunting experience awaits you in Monster Hunter Wilds.\r\n\r\nA few years past, a young boy named Nata was rescued at the border of the Forbidden Lands, an unexplored region the guild has yet to survey.\r\nAfter hearing the boy’s tale of his lone escape from a mysterious monster that attacked his village, the Guild organized an expedition into the Forbidden Lands to investigate.\r\n\r\nA Living World\r\n\r\nEnvironments within the Forbidden Lands can drastically change as the weather shifts constantly and suddenly. During the harsh Fallow and perilous Inclemency periods, ravenous monsters will venture out to hunt in packs, yet during the Plenty periods, wildlife is rich and abundant.\r\n\r\nMonsters\r\n\r\nThe monsters who inhabit these environments have been forced to adapt to the dynamic changes that occur, using their unique characteristics to survive and thrive.\r\n\r\nHunting\r\n\r\nAs the world around them changes, so must the hunters and their tactics. Not only will hunters have a multitude of weapons and armor to choose from, but the art of the hunt itself has evolved as hunters learn to anticipate monsters’ behavior and familiarize themselves with their environment.\r\n\r\nCharacters\r\n\r\nFrom hunting partners to fellow expedition members, you’ll encounter plenty of those who will support you on your journey.', '2026-04-11 16:21:56', '2026-04-11 16:21:56'),
('018dd749-4e61-73b3-8614-7fc1c787f5c7', 'Age of Mythology: Retold', 'Strategy', 209243, 'World\'s Edge, Forgotten Empires, Tantalus Media, Virtuos Games, CaptureAge, Virtuos', 'Xbox Game Studios, Microsoft, Xbox', 3518, 25879, 90, 10, 'https://assets.isthereanydeal.com/018dd749-4e61-73b3-8614-7fc1c787f5c7/banner300.jpg?t=1775674207', '2024-09-04 00:00:00', 'Gods will return. Heroes will rise. Legends will battle.', '2026-04-11 16:22:58', '2026-04-11 16:22:58'),
('018df3b7-b699-72dd-9dda-f215f7f444e1', 'Metaphor: ReFantazio', 'RPG', 799000, 'ATLUS Games, ATLUS', 'SEGA, ATLUS', 1722, 85961, 90, 10, 'https://assets.isthereanydeal.com/018df3b7-b699-72dd-9dda-f215f7f444e1/banner300.jpg?t=1764794710', '2024-02-29 00:00:00', 'From the creative minds behind Persona 3, 4, and 5 comes Metaphor: ReFantazio, a unique fantasy world, where your protagonist will journey alongside his fairy companion, Gallica, to lift the curse from the kingdom’s lost prince. Control your destiny, face your fears and awaken magical \"Archetype\" powers that lie dormant in your heart. By awakening to an “Archetype,” you will unlock the power to channel and combine the abilities of unique job classes. Strengthen your bonds and build your party to take down powerful foes and discover the kingdom’s true nature.\r\n\r\n-Go on uests, dungeon dive, & hunt for treasures by day. Strengthen relationships, build bonds, & increase virtues by night. Choose your actions wisely, time management is key to achieving your goal. \r\n\r\nRide your “gauntlet runner” to faraway dungeons & towns across an expansive world. Discover beautiful landscapes  accompanied by captivating music, immersive UI, & anime cutscenes.\r\n\r\nA unique battle system combining turn based & real time action grants strategy & exhilaration at every turn. Party customization through “Archetypes” provides freedom to personalize your adventure. \r\n\r\nA mysterious & exciting story unfolds in a world where people must fight their own anxiety. Join the high-stakes Royal Tournament that promises hours of captivating exploration and discovery.', '2026-04-11 16:25:01', '2026-04-11 16:25:01'),
('018f4953-3ed5-70b5-a582-94a4de019373', 'S.T.A.L.K.E.R. 2: Heart of Chornobyl', 'Open World', 465500, 'GSC Game World', 'GSC Game World, GSC Game World, SEGA, 4divinity, GSC Game World (worldwide), 4divinity (China and South East Asia), SEGA (Japan), GMG Label Limited, GSC Game World (worldwide)SEGA (Japan)4Divinity (China and South East', 7959, 121335, 81, 19, 'https://assets.isthereanydeal.com/018f4953-3ed5-70b5-a582-94a4de019373/banner300.jpg?t=1775816421', '2024-11-20 00:00:00', 'It’s a unique blend of FPS, immersive sim and horror with a really thick atmosphere. One of the biggest open-worlds to date is yours to explore — along with an epic branching story with multiple endings. Your choices will influence both short-term consequences and global outcomes.', '2026-04-11 16:23:03', '2026-04-11 16:23:03'),
('018f72b7-e912-70c5-8bc1-a493958bb3b6', 'Assassin\'s Creed Shadows', 'Action', 538815, 'Ubisoft Entertainment, Ubisoft Montreal, Ubisoft Montpellier, Ubisoft Sofia, Ubisoft Belgrade, Ubisoft Quebec, Ubisoft Singapore, Ubisoft Chengdu, Ubisoft Ukraine, Ubisoft Bordeaux, Ubisoft Osaka, Ubisoft Philippines, Ubisoft Shanghai, Ubisoft Bucharest & Craiova, Ubisoft', 'Ubisoft Entertainment, Ubisoft', 3817, 64825, 76, 24, 'https://assets.isthereanydeal.com/018f72b7-e912-70c5-8bc1-a493958bb3b6/banner300.jpg?t=1775590506', '2025-03-19 00:00:00', 'Live the intertwined stories of Naoe, an adept shinobi Assassin from Iga Province, and Yasuke, the powerful African samurai of historical legend. Against the backdrop of the turbulent late Sengoku period, this remarkable duo will discover their common destiny as they usher in a new era for Japan. Discover the captivating open world of feudal Japan, from spectacular castle towns and bustling ports to peaceful shrines and pastoral landscapes. Adventure through unpredictable weather, changing seasons, and reactive environments. As the quick-witted and agile Naoe, use noise, light, and shadows to evade detection as enemies respond to their changing surroundings. Distract guards using kunai, shuriken, and smoke bombs, infiltrate enemy bases with your grappling hook and parkour skills, and assassinate your targets with the hidden blade. As the charismatic samurai Yasuke, strike your foes with brutal precision and power. Use his combat-oriented skills to attack, block, parry, and defeat your enemies. Master the vast arsenal of weapons at your disposal – featuring katana, kanabo, bows, naginata, and more – to free Japan from its oppressors. Travel the world, explore, and scout your surroundings to gather vital intel. Build your network of spies to be your eyes and ears across locations to unveil new areas and hunt down your next target. Along the way, recruit several allies with highly specialized skills and abilities to help accomplish your missions. [Ubisoft]', '2026-04-11 16:23:39', '2026-04-11 16:23:39'),
('018ff49c-05f6-73d1-9ad6-0ebf81905107', 'Sid Meier\'s Civilization® VII', 'Grand Strategy', 799000, 'Firaxis Games, Firaxis', '2K, 2K Games, TAKE-TWO INTERACTIVE, Firaxis Games', 7663, 84558, 48, 52, 'https://assets.isthereanydeal.com/018ff49c-05f6-73d1-9ad6-0ebf81905107/banner300.jpg?t=1772734813', '2025-02-11 00:00:00', 'The award-winning strategy game franchise returns with a revolutionary new chapter. Sid Meier\'s Civilization VII empowers you to build the greatest empire the world has ever known!\r\n\r\nRule as one of many legendary leaders from throughout history. Establish your civilization, construct cities and architectural wonders to expand your territory, conquer or cooperate with rival civilizations in pursuit of prosperity, and explore the far reaches of the unknown world. \r\n\r\nWill you build an empire that stands the test of time?', '2026-04-11 16:22:50', '2026-04-11 16:22:50'),
('018ff4c4-e754-70fe-8a34-769902b69090', 'Wanderstop', 'Adventure', 254069, 'Ivy Road', 'Annapurna Interactive, Annapurna Games', 34, 1300, 92, 8, 'https://assets.isthereanydeal.com/018ff4c4-e754-70fe-8a34-769902b69090/banner300.jpg?t=1764017706', '2025-03-11 00:00:00', 'Wanderstop is a narrative-centric cozy game about change and tea. Playing as a fallen fighter named Alta, you’ll manage a tea shop within a magical forest and tend to the customers who pass through. But Alta does not want to be here. And if she gets her way, the tea shop will be nothing but a brief and painful memory.\r\n\r\nGrow and harvest the ingredients needed for tea, and then mix them together in an unusual tea-making contraption. Along the way, speak with the many travelers who pass through the shop, learn their stories and make tea that’s just right for them.', '2026-04-11 16:25:11', '2026-04-11 16:25:11'),
('018ffa67-6169-70eb-9e5c-717c0058904e', 'LivingForest', 'Racing', 83994, 'LivingEveryday', 'LivingEveryday', 921, 921, 75, 25, 'https://assets.isthereanydeal.com/018ffa67-6169-70eb-9e5c-717c0058904e/banner300.jpg?t=1775277612', '2024-11-03 00:00:00', 'In this forest, you can fight zombies and soldiers by picking up weapons.\r\n\r\nPlayers can use axes, pistols, gun to fight or collect resource and food. You also use resource build structure, and there some mission need finish.', '2026-04-11 16:22:14', '2026-04-11 16:22:14'),
('018ffe0d-15a7-7247-bb3c-4e5e1980561f', 'Clair Obscur: Expedition 33', 'Turn-Based Combat', 733039, 'Sandfall Interactive', 'Kepler Interactive, Sandfall Interactive, Kepler Interactive Limited', 11386, 145063, 95, 5, 'https://assets.isthereanydeal.com/018ffe0d-15a7-7247-bb3c-4e5e1980561f/banner300.jpg?t=1773677108', '2024-06-10 00:00:00', 'Once a year, the Paintress wakes and paints upon her monolith. Paints her cursed number. And everyone of that age turns to smoke and fades away. Year by year, that number ticks down and more of us are erased. Tomorrow she’ll wake and paint “33.” And tomorrow we depart on our final mission - Destroy the Paintress, so she can never paint death again. We are Expedition 33. Clair Obscur: Expedition 33 is a turn-based RPG with unique real-time mechanics, making battles more immersive and addictive than ever. Explore a fantasy world inspired by Belle Époque France in which you battle devastating enemies. In this evolution of JRPGs, real-time actions enhance the heart of turn-based combat. Craft unique builds for your Expeditioners that fit your playstyle via gear, stats, skills, and character synergies. Open an active dimension in combat - dodge, parry, and counter in real time, chain combos by mastering attack rhythms, and target enemy weak points using a free aim system. With only one year left to live, join Gustave, Maelle, and their fellow Expeditioners as they embark upon a desperate quest to break the Paintress’ cycle of death. Follow the trail of previous expeditions and discover their fate. Get to know the members of Expedition 33 as they learn to work together against impossible odds. Explore an enchanting realm populated by surreal adversaries. Wander through breathtaking landscapes, from the Island of Visages to the Forgotten Battlefield, discovering secrets and hidden quests along the way. Find allies of fortune in creatures of legend. Recruit special companions to access new travel methods and discover secret areas in the World Map.', '2026-04-11 16:21:35', '2026-04-11 16:21:35'),
('018ffe30-0af1-701c-b71a-24ca5e3c0d05', 'DOOM: The Dark Ages', 'Action', 1033732, 'id Software', 'Bethesda Softworks, Microsoft, Bethesda', 1056, 31470, 87, 13, 'https://assets.isthereanydeal.com/018ffe30-0af1-701c-b71a-24ca5e3c0d05/banner300.jpg?t=1768359618', '2025-05-15 00:00:00', 'Announcing DOOM: The Dark Ages, the prequel to the critically acclaimed DOOM (2016) and DOOM Eternal, and the third installment of the modern DOOM series. Developed by id Software on the latest idTech engine, DOOM: The Dark Ages is a single-player action FPS that tells the epic cinematic origin story of the DOOM Slayer\'s rage.\r\n\r\nYou are the DOOM Slayer, the legendary demon-killing warrior and the super weapon in this never-before-seen dark and sinister medieval war against Hell.', '2026-04-11 16:21:48', '2026-04-11 16:21:48'),
('01917100-2f57-70e4-8580-d881d5a099af', 'Borderlands 4', 'FPS', 799000, 'Gearbox Software, Gearbox', '2K, 2K Games, Gearbox Software, TAKE-TWO INTERACTIVE', 8282, 304398, 60, 40, 'https://assets.isthereanydeal.com/01917100-2f57-70e4-8580-d881d5a099af/banner300.jpg?t=1775586913', '2025-09-11 00:00:00', 'The definitive looter shooter arrives in 2025. \r\n\r\nSee if you have what it takes to go down in history as a legendary Vault Hunter as you search for secret alien treasure, blasting everything in sight.', '2026-04-11 16:22:06', '2026-04-11 16:22:06'),
('019809e3-e405-7052-b4f0-7a3e7259c766', 'Prop Sumo', 'Action', 0, 'Barrel Roll Games, Barrel Roll Games GmbH & Co. KG', 'Barrel Roll Games, Barrel Roll Games GmbH & Co. KG', 5, 6, NULL, NULL, 'https://assets.isthereanydeal.com/019809e3-e405-7052-b4f0-7a3e7259c766/banner300.jpg?t=1775751607', '2026-04-09 00:00:00', 'Prop Sumo is a party fighting game that pits ordinary props together in extraordinary battles! Beat up your friends and dominate the scoreboard!', '2026-04-11 16:21:46', '2026-04-11 16:21:46');
